package cr.ac.ucr.mediacloud.repository;
import cr.ac.ucr.mediacloud.model.*;import org.springframework.jdbc.core.*;import org.springframework.stereotype.Repository;import java.sql.*;import java.util.*;
@Repository public class UsuarioRepository{private final JdbcTemplate jdbc; public UsuarioRepository(JdbcTemplate jdbc){this.jdbc=jdbc;} private final RowMapper<Usuario> mapper=(rs,n)->{Usuario u=new Usuario();u.setId(rs.getInt("id"));u.setNombre(rs.getString("nombre"));u.setCorreo(rs.getString("correo"));u.setClave(rs.getString("clave"));u.setRol(Rol.valueOf(rs.getString("rol")));u.setActivo(rs.getBoolean("activo"));Timestamp t=rs.getTimestamp("fecha_creacion"); if(t!=null)u.setFechaCreacion(t.toLocalDateTime());return u;}; public Optional<Usuario> login(String correo,String clave){return jdbc.query("SELECT * FROM usuarios WHERE correo=? AND clave=SHA2(?,256) AND activo=TRUE",mapper,correo,clave).stream().findFirst();} public List<Usuario> listar(){return jdbc.query("SELECT * FROM usuarios ORDER BY id DESC",mapper);} public Optional<Usuario> buscar(Integer id){return jdbc.query("SELECT * FROM usuarios WHERE id=?",mapper,id).stream().findFirst();} public void guardar(Usuario u){jdbc.update("INSERT INTO usuarios(nombre,correo,clave,rol,activo) VALUES(?,?,SHA2(?,256),?,?)",u.getNombre(),u.getCorreo(),u.getClave(),u.getRol().name(),u.isActivo());} public void actualizar(Usuario u){jdbc.update("UPDATE usuarios SET nombre=?, correo=?, rol=?, activo=? WHERE id=?",u.getNombre(),u.getCorreo(),u.getRol().name(),u.isActivo(),u.getId());} public void desactivar(Integer id){jdbc.update("UPDATE usuarios SET activo=FALSE WHERE id=?",id);} public int total(){return jdbc.queryForObject("SELECT COUNT(*) FROM usuarios",Integer.class);} }
